def validate_cart_items(cart_items: List[CartItem]) -> float:
    if not cart_items:
        raise ValidationError("Cart is empty.")
    subtotal = 0.0
    for item in cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item.item_id}.")
        if item.unit_price < 0:
            raise ValidationError(f"Invalid price for item {item.item_id}.")
        subtotal += item.total()
    return subtotal


def apply_discount_code(
    subtotal: float,
    user: User,
    discount_code: Optional[str],
    available_discounts: Dict[str, DiscountCode],
) -> tuple[float, float, Optional[str]]:
    if not discount_code:
        return subtotal, 0.0, None

    discount = available_discounts.get(discount_code)
    if discount is None:
        raise DiscountError("Invalid discount code.")

    if not discount.is_allowed_for(user):
        raise PermissionError("User is not permitted to use this discount code.")

    discount_amount = subtotal * max(0.0, min(discount.percent_off, 1.0))
    discount_amount += max(0.0, discount.fixed_off)
    discount_amount = min(discount_amount, subtotal)

    discounted_subtotal = subtotal - discount_amount
    return discounted_subtotal, discount_amount, discount.code


def calculate_tax(amount: float, tax_rate: float) -> float:
    if amount < 0:
        raise ValidationError("Amount cannot be negative for tax calculation.")
    if tax_rate < 0:
        raise ValidationError("Tax rate cannot be negative.")
    return round(amount * tax_rate, 2)


def process_payment(amount: float, payment_method: Optional[Dict[str, Any]]) -> PaymentResult:
    if amount < 0:
        raise PaymentError("Cannot charge a negative amount.")
    if payment_method is None:
        raise PaymentError("Missing payment method.")

    if payment_method.get("type") == "card" and payment_method.get("token"):
        return PaymentResult(success=True, transaction_id=str(uuid.uuid4()), amount_charged=round(amount, 2))

    raise PaymentError("Payment failed.")


def create_order_record(
    user: User,
    cart_items: List[CartItem],
    subtotal: float,
    discount_amount: float,
    tax_amount: float,
    total: float,
    discount_code: Optional[str],
    payment_result: PaymentResult,
) -> OrderRecord:
    if not payment_result.success or not payment_result.transaction_id:
        raise CheckoutError("Cannot create order without successful payment.")

    items_data = [
        {
            "item_id": item.item_id,
            "name": item.name,
            "quantity": item.quantity,
            "unit_price": item.unit_price,
            "total": round(item.total(), 2),
        }
        for item in cart_items
    ]

    return OrderRecord(
        order_id=str(uuid.uuid4()),
        user_id=user.user_id,
        items=items_data,
        subtotal=round(subtotal, 2),
        discount_amount=round(discount_amount, 2),
        tax_amount=round(tax_amount, 2),
        total=round(total, 2),
        discount_code=discount_code,
        transaction_id=payment_result.transaction_id,
    )


def checkout_process(context: CheckoutContext) -> Dict[str, Any]:
    subtotal = validate_cart_items(context.cart_items)

    discounted_subtotal, discount_amount, applied_discount_code = apply_discount_code(
        subtotal=subtotal,
        user=context.user,
        discount_code=context.discount_code,
        available_discounts=context.available_discounts,
    )

    tax_amount = calculate_tax(discounted_subtotal, context.tax_rate)
    total = round(discounted_subtotal + tax_amount, 2)

    payment_result = process_payment(total, context.payment_method)

    order = create_order_record(
        user=context.user,
        cart_items=context.cart_items,
        subtotal=subtotal,
        discount_amount=discount_amount,
        tax_amount=tax_amount,
        total=total,
        discount_code=applied_discount_code,
        payment_result=payment_result,
    )

    return {
        "order": order,
        "payment": payment_result,
    }